module top_module(
    input inv_CK,
    input D,
    input RST,
    output reg Q,     // Changed Q to output reg
    output reg QN     // Changed QN to output reg
);always @(posedge inv_CK or negedge RST) begin
    if (!RST) begin
        Q <= 0;
        QN <= 1;
    end else begin
        Q <= D;
        QN <= ~D;
    end
end

endmodule
